<head> <meta charset="UTF-8"> <title>IPB Run 2026 Invoice</title> <style> * { margin: 0; padding: 0; box-sizing: border-box; } body { font-family: Arial, sans-serif; @if($bg_base64) background-image: url('{{ $bg_base64 }}'); @endif background-size: cover; background-position: center; color: white; padding: 20px; min-height: 100vh; } .invoice-container { max-width: 750px; margin: 0px auto; margin-top: 150px; background-color: rgba(0, 0, 0, 0.4); border-radius: 15px; border: 2px solid rgba(255, 255, 255, 0.3); overflow: hidden; } .header { text-align: center; padding: 30px 20px 20px; background-color: rgba(255, 255, 255, 0.1); margin-bottom: 20px; } .invoice-title { font-size: 42px; font-weight: bold; letter-spacing: 6px; margin-bottom: 25px; color: white; } .invoice-info { width: 100%; margin-bottom: 10px; } .invoice-info table { width: 100%; border-collapse: collapse; } .invoice-info td { padding: 8px 20px; font-size: 16px; font-weight: 500; } .invoice-info td:first-child { text-align: left; opacity: 0.9; } .invoice-info td:last-child { text-align: right; font-weight: bold; } .invoice-table { margin: 0 20px 30px; background-color: rgba(255, 255, 255, 0.1); border-radius: 10px; overflow: hidden; } .invoice-table table { width: 100%; border-collapse: collapse; } .table-header { background-color: rgba(255, 255, 255, 0.2); font-weight: bold; font-size: 18px; } .table-header td { padding: 18px 25px; border-bottom: 2px solid rgba(255, 255, 255, 0.4); } .table-row td { padding: 12px 25px; border-bottom: 1px solid rgba(255, 255, 255, 0.1); font-size: 16px; } .table-row:last-child td { border-bottom: none; } .item-name { font-weight: 500; } .item-total { font-weight: bold; text-align: right; } .discount { color: #4ecdc4; } .donation { color: #ffd93d; } .total-row { background-color: rgba(255, 255, 255, 0.2); font-size: 20px; font-weight: bold; border-top: 3px solid rgba(255, 255, 255, 0.3); } .total-row td { padding: 20px 25px; } .footer { text-align: center; padding: 25px 20px; background-color: rgba(255, 255, 255, 0.05); border-top: 1px solid rgba(255, 255, 255, 0.1); } .contact-info { font-size: 16px; line-height: 1.8; } .contact-item { margin: 8px 0; } /* DomPDF specific styles */ @page { margin: 0; } </style>
