<body> <div class="invoice-container"> <div class="header"> <h1 class="invoice-title">INVOICE</h1> <div class="invoice-info"> <table> <tr> <td>FULL NAME : <strong>{{ $participant->name }}</strong></td> <td>ORDER CODE : <strong>#{{ $order->order_code }}</strong></td> </tr> </table> </div> </div> <div class="invoice-table"> <table> <tr class="table-header"> <td>ITEM</td> <td class="item-total">TOTAL</td> </tr> @foreach($order->raceEntries as $entry) <tr class="table-row"> <td class="item-name"> {{ $entry->ticket->category->name }} ({{ $entry->ticket->name ?: strtoupper($entry->ticket->type) }}) </td> <td class="item-total"> IDR {{ number_format($entry->ticket->price, 0, ',', ',') }} </td> </tr> @endforeach @if($order->donation_scholarship > 0) <tr class="table-row donation"> <td class="item-name">Donation for Scholarship</td> <td class="item-total">IDR {{ number_format($order->donation_scholarship, 0, ',', ',') }}</td> </tr> @endif @if($order->donation_event > 0) <tr class="table-row donation"> <td class="item-name">Donation for Event</td> <td class="item-total">IDR {{ number_format($order->donation_event, 0, ',', ',') }}</td> </tr> @endif <tr class="table-row"> <td class="item-name">Transaction Fee</td> <td class="item-total">IDR 4,500</td> </tr> <tr class="table-row total-row"> <td>Total Paid</td> <td class="item-total">IDR {{ number_format($order->total_price, 0, ',', ',') }}</td> </tr> </table> </div> <div class="footer"> <div class="contact-info"> <div class="contact-item"><span>+62 8567922780</span></div> <div class="contact-item"><span>+62 811-1231-088</span></div> <div class="contact-item"><span>ipbrun2026.id</span></div> </div> </div> </div>
